contracts/InsurancePool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title InsurancePool
 * @notice Protection fund for users affected by incorrect event resolutions.
 *
 * Flow:
 * 1. Pool is funded from a portion of platform fees or direct deposits.
 * 2. Users can file claims against specific event IDs with evidence.
 * 3. Arbiters (ARBITER_ROLE) approve or deny claims.
 * 4. Approved claims pay out from the pool balance.
 *
 * Caps: max payout per claim = 10% of pool balance.
 * Cooldown: 24h between claims per user.
 */
contract InsurancePool is AccessControl, ReentrancyGuard {
    bytes32 public constant ARBITER_ROLE = keccak256("ARBITER_ROLE");

    enum ClaimStatus { Pending, Approved, Denied, Paid }

    struct Claim {
        uint256 id;
        address claimant;
        uint256 eventId;
        uint256 amount;         // requested amount
        uint256 approvedAmount; // amount approved by arbiter
        string reason;
        ClaimStatus status;
        uint256 filedAt;
        uint256 resolvedAt;
    }

    uint256 public claimCount;
    uint256 public totalPaidOut;
    uint256 public maxPayoutBps = 1000; // 10% of pool balance per claim
    uint256 public claimCooldown = 1 days;

    mapping(uint256 => Claim) public claims;
    mapping(address => uint256) public lastClaimAt;
    mapping(address => uint256[]) public userClaims;
    // eventId => total claims filed
    mapping(uint256 => uint256) public eventClaimCount;

    event PoolFunded(address indexed funder, uint256 amount);
    event ClaimFiled(uint256 indexed claimId, address indexed claimant, uint256 eventId, uint256 amount);
    event ClaimApproved(uint256 indexed claimId, uint256 approvedAmount);
    event ClaimDenied(uint256 indexed claimId);
    event ClaimPaid(uint256 indexed claimId, address indexed claimant, uint256 amount);
    event MaxPayoutUpdated(uint256 oldBps, uint256 newBps);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(ARBITER_ROLE, msg.sender);
    }

    // ─── Funding ────────────────────────────────────────────────

    receive() external payable {
        emit PoolFunded(msg.sender, msg.value);
    }

    function fund() external payable {
        require(msg.value > 0, "Zero deposit");
        emit PoolFunded(msg.sender, msg.value);
    }

    // ─── File Claim ─────────────────────────────────────────────

    function fileClaim(uint256 eventId, uint256 requestedAmount, string calldata reason)
        external
        returns (uint256)
    {
        require(requestedAmount > 0, "Zero amount");
        require(bytes(reason).length > 10 && bytes(reason).length <= 500, "Invalid reason");
        require(
            block.timestamp >= lastClaimAt[msg.sender] + claimCooldown,
            "Claim cooldown active"
        );

        uint256 maxPayout = (address(this).balance * maxPayoutBps) / 10000;
        require(requestedAmount <= maxPayout, "Exceeds max payout");

        claimCount++;
        claims[claimCount] = Claim({
            id: claimCount,
            claimant: msg.sender,
            eventId: eventId,
            amount: requestedAmount,
            approvedAmount: 0,
            reason: reason,
            status: ClaimStatus.Pending,
            filedAt: block.timestamp,
            resolvedAt: 0
        });

        lastClaimAt[msg.sender] = block.timestamp;
        userClaims[msg.sender].push(claimCount);
        eventClaimCount[eventId]++;

        emit ClaimFiled(claimCount, msg.sender, eventId, requestedAmount);
        return claimCount;
    }

    // ─── Arbiter Actions ────────────────────────────────────────

    function approveClaim(uint256 claimId, uint256 approvedAmount)
        external
        onlyRole(ARBITER_ROLE)
    {
        Claim storage c = claims[claimId];
        require(c.id != 0, "Claim not found");
        require(c.status == ClaimStatus.Pending, "Not pending");
        require(approvedAmount > 0 && approvedAmount <= c.amount, "Invalid amount");

        uint256 maxPayout = (address(this).balance * maxPayoutBps) / 10000;
        require(approvedAmount <= maxPayout, "Exceeds pool cap");

        c.approvedAmount = approvedAmount;
        c.status = ClaimStatus.Approved;
        c.resolvedAt = block.timestamp;

        emit ClaimApproved(claimId, approvedAmount);
    }

    function denyClaim(uint256 claimId) external onlyRole(ARBITER_ROLE) {
        Claim storage c = claims[claimId];
        require(c.id != 0, "Claim not found");
        require(c.status == ClaimStatus.Pending, "Not pending");

        c.status = ClaimStatus.Denied;
        c.resolvedAt = block.timestamp;

        emit ClaimDenied(claimId);
    }

    // ─── Claim Payout ───────────────────────────────────────────

    function claimPayout(uint256 claimId) external nonReentrant {
        Claim storage c = claims[claimId];
        require(c.id != 0, "Claim not found");
        require(c.status == ClaimStatus.Approved, "Not approved");
        require(msg.sender == c.claimant, "Not claimant");
        require(address(this).balance >= c.approvedAmount, "Insufficient pool balance");

        c.status = ClaimStatus.Paid;
        totalPaidOut += c.approvedAmount;

        (bool ok, ) = payable(c.claimant).call{value: c.approvedAmount}("");
        require(ok, "Transfer failed");

        emit ClaimPaid(claimId, c.claimant, c.approvedAmount);
    }

    // ─── View ───────────────────────────────────────────────────

    function getClaim(uint256 claimId) external view returns (Claim memory) {
        return claims[claimId];
    }

    function getUserClaims(address user) external view returns (uint256[] memory) {
        return userClaims[user];
    }

    function getPoolBalance() external view returns (uint256) {
        return address(this).balance;
    }

    function getPoolStats()
        external
        view
        returns (uint256 balance, uint256 totalClaims, uint256 paid, uint256 maxSinglePayout)
    {
        balance = address(this).balance;
        totalClaims = claimCount;
        paid = totalPaidOut;
        maxSinglePayout = (balance * maxPayoutBps) / 10000;
    }

    // ─── Admin ──────────────────────────────────────────────────

    function setMaxPayout(uint256 newBps) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newBps > 0 && newBps <= 5000, "Invalid max payout"); // 0.01% to 50%
        uint256 oldBps = maxPayoutBps;
        maxPayoutBps = newBps;
        emit MaxPayoutUpdated(oldBps, newBps);
    }

    function setClaimCooldown(uint256 seconds_) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(seconds_ <= 7 days, "Too long");
        claimCooldown = seconds_;
    }

    function emergencyWithdraw(address to) external onlyRole(DEFAULT_ADMIN_ROLE) nonReentrant {
        require(to != address(0), "Zero address");
        uint256 bal = address(this).balance;
        require(bal > 0, "Empty pool");
        (bool ok, ) = payable(to).call{value: bal}("");
        require(ok, "Transfer failed");
    }
}

contracts/OracleGovernance.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title OracleGovernance
 * @notice Lightweight on-chain governance for OracleAI platform parameters.
 *         OAI token holders can create and vote on proposals.
 *
 * Proposal types: parameter changes, fee adjustments, treasury allocations.
 * Voting power = OAI balance at snapshot (no delegation in v1).
 * Quorum = 1% of total supply. Voting period = 3 days.
 */
contract OracleGovernance is AccessControl {
    IERC20 public oaiToken;

    uint256 public constant VOTING_PERIOD = 3 days;
    uint256 public constant MIN_PROPOSAL_THRESHOLD = 10_000 ether; // 10K OAI to propose
    uint256 public quorumBps = 100; // 1% of total supply

    enum ProposalState { Pending, Active, Defeated, Succeeded, Executed, Cancelled }

    struct Proposal {
        uint256 id;
        address proposer;
        string title;
        string description;
        uint256 forVotes;
        uint256 againstVotes;
        uint256 startTime;
        uint256 endTime;
        bool executed;
        bool cancelled;
        bytes callData;    // optional: encoded function call for execution
        address target;    // optional: target contract for execution
    }

    uint256 public proposalCount;
    mapping(uint256 => Proposal) public proposals;
    mapping(uint256 => mapping(address => bool)) public hasVoted;
    mapping(uint256 => mapping(address => uint256)) public voteWeight;

    event ProposalCreated(
        uint256 indexed id,
        address indexed proposer,
        string title,
        uint256 startTime,
        uint256 endTime
    );
    event VoteCast(uint256 indexed proposalId, address indexed voter, bool support, uint256 weight);
    event ProposalExecuted(uint256 indexed id);
    event ProposalCancelled(uint256 indexed id);
    event QuorumUpdated(uint256 oldBps, uint256 newBps);

    constructor(address _oaiToken) {
        require(_oaiToken != address(0), "Zero token");
        oaiToken = IERC20(_oaiToken);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    // ─── Propose ────────────────────────────────────────────────

    function propose(
        string calldata title,
        string calldata description,
        address target,
        bytes calldata callData
    ) external returns (uint256) {
        require(
            oaiToken.balanceOf(msg.sender) >= MIN_PROPOSAL_THRESHOLD,
            "Below proposal threshold"
        );
        require(bytes(title).length > 0 && bytes(title).length <= 200, "Invalid title");

        proposalCount++;
        uint256 startTime = block.timestamp;
        uint256 endTime = startTime + VOTING_PERIOD;

        proposals[proposalCount] = Proposal({
            id: proposalCount,
            proposer: msg.sender,
            title: title,
            description: description,
            forVotes: 0,
            againstVotes: 0,
            startTime: startTime,
            endTime: endTime,
            executed: false,
            cancelled: false,
            callData: callData,
            target: target
        });

        emit ProposalCreated(proposalCount, msg.sender, title, startTime, endTime);
        return proposalCount;
    }

    // ─── Vote ───────────────────────────────────────────────────

    function castVote(uint256 proposalId, bool support) external {
        Proposal storage p = proposals[proposalId];
        require(p.id != 0, "Proposal not found");
        require(block.timestamp >= p.startTime && block.timestamp < p.endTime, "Voting closed");
        require(!p.cancelled, "Cancelled");
        require(!hasVoted[proposalId][msg.sender], "Already voted");

        uint256 weight = oaiToken.balanceOf(msg.sender);
        require(weight > 0, "No voting power");

        hasVoted[proposalId][msg.sender] = true;
        voteWeight[proposalId][msg.sender] = weight;

        if (support) {
            p.forVotes += weight;
        } else {
            p.againstVotes += weight;
        }

        emit VoteCast(proposalId, msg.sender, support, weight);
    }

    // ─── Execute ────────────────────────────────────────────────

    function execute(uint256 proposalId) external {
        Proposal storage p = proposals[proposalId];
        require(p.id != 0, "Proposal not found");
        require(block.timestamp >= p.endTime, "Voting not ended");
        require(!p.executed, "Already executed");
        require(!p.cancelled, "Cancelled");
        require(state(proposalId) == ProposalState.Succeeded, "Not succeeded");

        p.executed = true;

        if (p.target != address(0) && p.callData.length > 0) {
            (bool ok, ) = p.target.call(p.callData);
            require(ok, "Execution failed");
        }

        emit ProposalExecuted(proposalId);
    }

    function cancel(uint256 proposalId) external {
        Proposal storage p = proposals[proposalId];
        require(p.id != 0, "Proposal not found");
        require(
            msg.sender == p.proposer || hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Not authorized"
        );
        require(!p.executed, "Already executed");

        p.cancelled = true;
        emit ProposalCancelled(proposalId);
    }

    // ─── View ───────────────────────────────────────────────────

    function state(uint256 proposalId) public view returns (ProposalState) {
        Proposal memory p = proposals[proposalId];
        if (p.id == 0) return ProposalState.Pending;
        if (p.cancelled) return ProposalState.Cancelled;
        if (p.executed) return ProposalState.Executed;
        if (block.timestamp < p.endTime) return ProposalState.Active;

        // Check quorum: forVotes + againstVotes >= quorum % of total supply
        uint256 totalVotes = p.forVotes + p.againstVotes;
        uint256 quorum = (oaiToken.totalSupply() * quorumBps) / 10000;

        if (totalVotes < quorum) return ProposalState.Defeated;
        if (p.forVotes > p.againstVotes) return ProposalState.Succeeded;
        return ProposalState.Defeated;
    }

    function getProposal(uint256 proposalId) external view returns (Proposal memory) {
        return proposals[proposalId];
    }

    function getVoteInfo(uint256 proposalId, address voter)
        external
        view
        returns (bool voted, uint256 weight, bool support)
    {
        voted = hasVoted[proposalId][voter];
        weight = voteWeight[proposalId][voter];
        // Determine support from vote weight allocation
        // Note: we don't store direction separately, but we can infer it's not retrievable
        // without additional storage. For v1 this is acceptable.
        support = false; // would need extra mapping for per-voter direction
    }

    // ─── Admin ──────────────────────────────────────────────────

    function setQuorum(uint256 newBps) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newBps > 0 && newBps <= 5000, "Invalid quorum"); // 0.01% to 50%
        uint256 oldBps = quorumBps;
        quorumBps = newBps;
        emit QuorumUpdated(oldBps, newBps);
    }
}

